import { Value } from './engine.ts'

export class Module {
  zeroGrad() {
    for (const p of this.parameters()) p.grad = 0
  }
  parameters() {
    return []
  }
}

export class Neuron extends Module {
  b = new Value(0)

  constructor(nin, nonlin = true, rand = Math.random) {
    super()
    this.w = Array.from({ length: nin }, () => new Value(rand() * 2 - 1))
    this.nonlin = nonlin
  }

  call(x) {
    let act = this.b
    for (let i = 0; i < this.w.length; i++) act = act.add(this.w[i].mul(x[i]))
    return this.nonlin ? act.relu() : act
  }

  parameters() {
    return [...this.w, this.b]
  }
}

export class Layer extends Module {
  constructor(nin, nout, nonlin = true, rand = Math.random) {
    super()
    this.neurons = Array.from({ length: nout }, () => new Neuron(nin, nonlin, rand))
  }

  call(x) {
    return this.neurons.map((n) => n.call(x))
  }

  parameters() {
    return this.neurons.flatMap((n) => n.parameters())
  }
}

export class MLP extends Module {
  constructor(nin, nouts, rand = Math.random) {
    super()
    const sz = [nin, ...nouts]
    this.layers = sz.slice(0, -1).map((_, i) => new Layer(sz[i], sz[i + 1], i !== nouts.length - 1, rand))
  }

  call(x) {
    let out = x
    for (const layer of this.layers) out = layer.call(out)
    return out
  }

  parameters() {
    return this.layers.flatMap((l) => l.parameters())
  }
}

